import { ChangeDetectionStrategy, Component, computed, effect, inject, signal, ViewChild } from '@angular/core';
import { Router, NavigationEnd, RouterOutlet } from '@angular/router';
import { filter } from 'rxjs';
import { toSignal } from '@angular/core/rxjs-interop';

import { AuthService } from '../../services/auth.service';
import { BreadcrumbItem } from '../../types';
import { CloudEdgeSidebarComponent } from './components/sidebar/sidebar.component';
import { CloudEdgeTopBarComponent } from './components/top-bar/top-bar.component';
import { BreadcrumbsComponent } from '../../components/breadcrumbs/breadcrumbs.component';
import { MarketplaceService } from '../../pages/marketplace/services/marketplace.service';
import { ForumService } from '../../pages/community-forum/forum.service';
import { CommonModule } from '@angular/common';
import { IconComponent } from '../../components/icon/icon.component';

@Component({
  selector: 'app-cloud-edge-layout',
  templateUrl: './cloud-edge-layout.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CloudEdgeSidebarComponent, CloudEdgeTopBarComponent, RouterOutlet, BreadcrumbsComponent, CommonModule, IconComponent],
})
export class CloudEdgeLayoutComponent {
  @ViewChild(RouterOutlet) outlet!: RouterOutlet;
  private authService = inject(AuthService);
  // FIX: Explicitly type router to fix a type inference issue where it was being inferred as 'unknown'.
  private router: Router = inject(Router);
  private marketplaceService = inject(MarketplaceService);
  private forumService = inject(ForumService);

  isSidebarCollapsed = signal<boolean>(localStorage.getItem('cloudEdgeSidebarCollapsed') === 'true');

  user = this.authService.user;

  appLauncherItems = computed(() => this.authService.getAppLauncherItems(this.user()?.role));

  breadcrumbItems = signal<BreadcrumbItem[]>([]);
  isGettingStartedPage = signal(false);
  isDistributedFirewallOldPage = signal(false);

  private marketplaceItems = toSignal(this.marketplaceService.getItems(), { initialValue: [] });
  private marketplaceCategories = toSignal(this.marketplaceService.getCategories(), { initialValue: [] });

  constructor() {
    effect(() => {
      localStorage.setItem('cloudEdgeSidebarCollapsed', String(this.isSidebarCollapsed()));
    });

    this.router.events.pipe(
      filter((event): event is NavigationEnd => event instanceof NavigationEnd)
    ).subscribe((event: NavigationEnd) => {
      this.updateBreadcrumbs(event.urlAfterRedirects);
      this.isGettingStartedPage.set(event.urlAfterRedirects.includes('getting-started'));
      this.isDistributedFirewallOldPage.set(event.urlAfterRedirects.includes('distributed-firewall-old'));
    });

    this.updateBreadcrumbs(this.router.url);
    this.isGettingStartedPage.set(this.router.url.includes('getting-started'));
    this.isDistributedFirewallOldPage.set(this.router.url.includes('distributed-firewall-old'));
  }

  toggleSidebar(): void {
    this.isSidebarCollapsed.update(v => !v);
  }

  onAddPolicyClick(): void {
    if (this.outlet && this.outlet.isActivated) {
      const componentInstance = this.outlet.component as any;
      if (componentInstance && typeof componentInstance.handleAddPolicyClick === 'function') {
        componentInstance.handleAddPolicyClick();
      }
    }
  }

  private updateBreadcrumbs(url: string): void {
    const urlWithoutHash = url.startsWith('/#') ? url.substring(2) : url;
    const pathnames = urlWithoutHash.split('?')[0].split('/').filter(x => x && x !== 'app');

    const BREADCRUMB_LABELS: { [key: string]: string } = {
        'cloud-edge': 'CloudEdge', 'security': 'Security', 'overview': 'Security Overview',
        'hub': 'Security Hub', 'suspicious-traffic': 'Suspicious Traffic', 'filtering-analysis': 'Filtering and Analysis',
        'distributed-firewall': 'Distributed Firewall', 'add-policy': 'Distributed Firewall Policy', 'gateway-firewall': 'Gateway Firewall', 'hub-malware-prevention': 'IDS/IPS & Malware Prevention',
        'administration': 'Administration', 'organizations': 'Organizations', 'applications': 'Applications', 'inventory': 'Inventory',
        'firewall-groups': 'Groups', 'firewall-services': 'Services', 'virtual-machines': 'Virtual Machines',
        'create': 'Create Virtual Machine', 'images': 'Select OS Image', 'resources': 'Resources', 'network': 'Network',
        'operations': 'Operations', 'marketplace': 'Marketplace', 'community-forum': 'Community Forum'
    };

    const getLabel = (value: string) => BREADCRUMB_LABELS[value] || value.replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase());

    if (!pathnames.includes('cloud-edge')) {
        this.breadcrumbItems.set([]);
        return;
    };

    // --- Special handling for Community Forum ---
    if (pathnames.includes('community-forum')) {
        const crumbs: BreadcrumbItem[] = [
            { label: 'Home', path: '/app/cloud-edge' },
            { label: 'Resources', path: '/app/cloud-edge/resources/virtual-machines' },
            { label: 'Community Forum', path: '/app/cloud-edge/resources/community-forum' },
        ];

        const topicIndex = pathnames.indexOf('topic');

        if (topicIndex !== -1 && topicIndex + 1 < pathnames.length) {
            const topicId = pathnames[topicIndex + 1];
            const topicData = this.forumService.getTopicById(topicId);
            if (topicData) {
                crumbs.push({ label: topicData.topic.title });
            }
        }

        if (crumbs.length > 1) {
            delete crumbs[crumbs.length - 1].path;
        }

        this.breadcrumbItems.set(crumbs);
        return;
    }

    // --- Special handling for Marketplace ---
    if (pathnames.includes('marketplace')) {
        const crumbs: BreadcrumbItem[] = [
            { label: 'Home', path: '/app/cloud-edge' },
            { label: 'Resources', path: '/app/cloud-edge/resources/virtual-machines' },
            { label: 'Marketplace', path: '/app/cloud-edge/resources/marketplace' },
        ];

        const categoryIndex = pathnames.indexOf('category');
        const configureIndex = pathnames.indexOf('configure');

        if (categoryIndex !== -1 && categoryIndex + 1 < pathnames.length) {
            const categoryId = pathnames[categoryIndex + 1];
            const category = this.marketplaceCategories().find(c => c.id === categoryId);
            if (category) {
                crumbs.push({ label: category.name });
            }
        } else if (configureIndex !== -1 && configureIndex + 1 < pathnames.length) {
            const itemId = pathnames[configureIndex + 1];
            const item = this.marketplaceItems().find(i => i.id === itemId);
            if (item) {
                const category = this.marketplaceCategories().find(c => c.id === item.category);
                if (category) {
                    crumbs.push({ label: category.name, path: `/app/cloud-edge/resources/marketplace/category/${category.id}` });
                }
                crumbs.push({ label: item.name });
            }
        }

        if (crumbs.length > 1) {
            delete crumbs[crumbs.length - 1].path;
        }

        this.breadcrumbItems.set(crumbs);
        return;
    }


    const crumbs: BreadcrumbItem[] = [{ label: 'Home', path: '/app/cloud-edge' }];
    const segmentsToProcess = pathnames.slice(1);
    const sectionPaths = ['administration', 'resources', 'network', 'inventory', 'security', 'operations'];

    let currentPath = '/app/cloud-edge';
    segmentsToProcess.forEach((value) => {
      // We still need to build the full path for links.
      const fullPathForSegment = currentPath + `/${value}`;
      currentPath = fullPathForSegment;

      // But we only add a breadcrumb item if it's not a section path.
      if (!sectionPaths.includes(value)) {
        const label = getLabel(value);
        crumbs.push({ label, path: fullPathForSegment });
      }
    });

    if (crumbs.length > 1) {
        delete crumbs[crumbs.length - 1].path;
    }

    this.breadcrumbItems.set(crumbs);
  }
}

import { ChangeDetectionStrategy, Component, computed, signal, effect, ElementRef, viewChild, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { IconComponent } from '../../components/icon/icon.component';
import { ToggleSwitchComponent } from './components/toggle-switch/toggle-switch.component';
import { ViewMembersModalComponent } from './components/view-members-modal/view-members-modal.component';
import { EditSourceDestModalComponent } from './components/edit-source-dest-modal/edit-source-dest-modal.component';
import { EditAppliedToModalComponent } from './components/edit-applied-to-modal/edit-applied-to-modal.component';
import { RelatedGroupsModalComponent } from './components/related-groups-modal/related-groups-modal.component';
import { EditServicesModalComponent } from './components/edit-services-modal/edit-services-modal.component';
import { EditRuleAppliedToModalComponent } from './components/edit-rule-applied-to-modal/edit-rule-applied-to-modal.component';
import { AppliedToDisplayComponent } from './components/applied-to-display/applied-to-display.component';
import { FirewallPolicy, FirewallRule, GroupData, SelectableGroup, Service } from './types';
import { mockPoliciesData, mockGroupData, mockAvailableGroupsForSelection, mockAvailableServices } from './mock-data';
import { AdvancedDeleteConfirmationModalComponent } from '../../components/advanced-delete-confirmation-modal/advanced-delete-confirmation-modal.component';
import { ActivatedRoute, Router } from '@angular/router';

@Component({
  selector: 'app-distributed-firewall',
  templateUrl: './distributed-firewall.component.html',
  styleUrls: ['./distributed-firewall.component.css'],
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    CommonModule,
    FormsModule,
    IconComponent,
    ToggleSwitchComponent,
    AdvancedDeleteConfirmationModalComponent,
    ViewMembersModalComponent,
    EditSourceDestModalComponent,
    EditAppliedToModalComponent,
    RelatedGroupsModalComponent,
    EditServicesModalComponent,
    EditRuleAppliedToModalComponent,
    AppliedToDisplayComponent,
  ],
  host: {
    '(document:mousedown)': 'onGlobalClick($event)',
  },
})
export class DistributedFirewallComponent {
  private router = inject(Router);
  private route = inject(ActivatedRoute);

  // Main state
  policies = signal<FirewallPolicy[]>(mockPoliciesData);
  selectedItems = signal<string[]>([]);

  // Available data for modals
  availableGroups = signal<SelectableGroup[]>(mockAvailableGroupsForSelection);
  availableServices = signal<{ name: string; icon: string }[]>(mockAvailableServices);

  // New rule state
  addingRuleToPolicyId = signal<string | null>(null);
  newRuleForm = signal(this.getInitialNewRuleState());

  // Modal states
  isDeleteModalOpen = signal(false);
  isViewMembersModalOpen = signal(false);
  viewingGroup = signal<GroupData | null>(null);
  isRelatedGroupsModalOpen = signal(false);
  viewingRelatedGroup = signal<SelectableGroup | null>(null);

  editSourceDestModalState = signal<{ isOpen: boolean; rule: FirewallRule | null; policyId: string | null; field: 'sources' | 'destinations' | null; isNewRule?: boolean }>({ isOpen: false, rule: null, policyId: null, field: null });
  editAppliedToModalState = signal<{ isOpen: boolean; policy: FirewallPolicy | null }>({ isOpen: false, policy: null });
  editServicesModalState = signal<{ isOpen: boolean; rule: FirewallRule | null; policyId: string | null }>({ isOpen: false, rule: null, policyId: null });
  editRuleAppliedToModalState = signal<{ isOpen: boolean; rule: FirewallRule | null; policy: FirewallPolicy | null }>({ isOpen: false, rule: null, policy: null });
  modalSource = signal<'sourceDest' | 'appliedTo' | 'ruleAppliedTo' | null>(null);

  isActionsMenuOpen = signal(false);
  actionsMenuRef = viewChild<ElementRef>('actionsMenuRef');
  actionsButtonRef = viewChild<ElementRef>('actionsButtonRef');

  // Computed properties
  isSelectionEmpty = computed(() => this.selectedItems().length === 0);
  isSingleSelection = computed(() => this.selectedItems().length === 1);
  isSinglePolicySelected = computed(() => {
    if (!this.isSingleSelection()) return false;
    const selectedId = this.selectedItems()[0];
    return this.policies().some(p => p.id === selectedId);
  });

  constructor() {
    effect(() => {
      // Auto-expand policy when adding a new rule to it
      const policyId = this.addingRuleToPolicyId();
      if (policyId) {
        const policy = this.policies().find(p => p.id === policyId);
        if (policy && !policy.isExpanded) {
          this.togglePolicy(policyId);
        }
      }
    });
  }

  onGlobalClick(event: MouseEvent): void {
      if (
          this.isActionsMenuOpen() &&
          this.actionsMenuRef() && !this.actionsMenuRef()!.nativeElement.contains(event.target as Node) &&
          this.actionsButtonRef() && !this.actionsButtonRef()!.nativeElement.contains(event.target as Node)
      ) {
          this.isActionsMenuOpen.set(false);
      }
  }

  getInitialNewRuleState() {
    return {
      name: '',
      sources: 'Any',
      destinations: 'Any',
      services: [{ name: 'Any', icon: 'fas fa-asterisk' }],
      action: 'Allow' as 'Allow' | 'Deny' | 'Drop',
      enabled: true,
      contextProfiles: 'None',
      appliedTo: 'DFW'
    };
  }

  // --- Main Actions ---

  handleAddPolicyClick(): void {
    this.router.navigate(['add-policy'], { relativeTo: this.route });
  }

  handleAddRuleClick(): void {
    if (this.isSinglePolicySelected()) {
      const policyId = this.selectedItems()[0];
      this.addingRuleToPolicyId.set(policyId);
      const policyName = this.policies().find(p => p.id === policyId)?.name || '';
      this.newRuleForm.set({ ...this.getInitialNewRuleState(), name: `New Rule in ${policyName}` });
    }
  }

  handleCancelNewRule(): void {
    this.addingRuleToPolicyId.set(null);
  }

  handleSaveNewRule(): void {
    const policyId = this.addingRuleToPolicyId();
    const formState = this.newRuleForm();
    if (!policyId || !formState.name.trim()) return;

    const newRule: FirewallRule = {
      id: `rule-${Date.now()}`,
      ruleId: String(Math.floor(Math.random() * 100) + 10),
      ...formState
    };

    this.policies.update(prev => prev.map(p => 
      p.id === policyId ? { ...p, rules: [newRule, ...p.rules] } : p
    ));
    this.handleCancelNewRule();
  }

  handleDeleteClick(): void {
    if (this.isSelectionEmpty()) return;
    this.isDeleteModalOpen.set(true);
  }

  handleConfirmDelete(): void {
    const selected = this.selectedItems();
    this.policies.update(prev => {
        const remainingPolicies = prev.filter(p => !selected.includes(p.id));
        return remainingPolicies.map(p => ({
            ...p,
            rules: p.rules.filter(r => !selected.includes(r.id))
        }));
    });
    this.selectedItems.set([]);
    this.isDeleteModalOpen.set(false);
  }

  // --- Table Interactions ---

  togglePolicy(policyId: string): void {
    this.policies.update(ps => ps.map(p => p.id === policyId ? { ...p, isExpanded: !p.isExpanded } : p));
  }

  handleSelect(id: string, event: Event): void {
    const isChecked = (event.target as HTMLInputElement).checked;
    this.selectedItems.update(prev => 
      isChecked ? [...prev, id] : prev.filter(i => i !== id)
    );
  }

  handleRuleUpdate(policyId: string, ruleId: string, field: keyof Omit<FirewallRule, 'id' | 'ruleId'>, value: any): void {
    this.policies.update(ps => ps.map(p => {
        if (p.id === policyId) {
            return { ...p, rules: p.rules.map(r => r.id === ruleId ? { ...r, [field]: value } : r) };
        }
        return p;
    }));
  }

  handlePolicyUpdate(policyId: string, field: keyof Omit<FirewallPolicy, 'id' | 'rules'>, value: any): void {
      this.policies.update(ps => ps.map(p => p.id === policyId ? { ...p, [field]: value } : p));
  }

  getServiceNames(services: Service[]): string {
    return services.map(s => s.name).join(', ');
  }

  handleNewRuleEnabledChange(enabled: boolean): void {
    this.newRuleForm.update(form => ({ ...form, enabled }));
  }

  // --- Modal Opening ---

  handleOpenViewMembersModal(groupName: string, source: 'sourceDest' | 'appliedTo' | 'ruleAppliedTo'): void {
    const groupData = mockGroupData[groupName];
    if (groupData) {
      this.viewingGroup.set(groupData);
      if (source === 'sourceDest') {
        this.editSourceDestModalState.update(s => ({ ...s, isOpen: false }));
      } else if (source === 'appliedTo') {
        this.editAppliedToModalState.update(s => ({ ...s, isOpen: false }));
      } else { // ruleAppliedTo
        this.editRuleAppliedToModalState.update(s => ({ ...s, isOpen: false }));
      }
      this.isViewMembersModalOpen.set(true);
      this.modalSource.set(source);
    }
  }

  handleOpenRelatedGroupsModal(group: SelectableGroup): void {
    this.viewingRelatedGroup.set(group);
    this.isRelatedGroupsModalOpen.set(true);
  }

  handleOpenEditSourceDestModal(rule: FirewallRule, policyId: string, field: 'sources' | 'destinations'): void {
    this.editSourceDestModalState.set({ isOpen: true, rule, policyId, field });
  }

  handleOpenEditSourceDestModalForNewRule(field: 'sources' | 'destinations'): void {
    const policyId = this.addingRuleToPolicyId();
    if (!policyId) return;
    const formState = this.newRuleForm();
    const tempRule: FirewallRule = { id: 'new-rule', ruleId: 'new', ...formState };
    this.editSourceDestModalState.set({ isOpen: true, rule: tempRule, policyId, field, isNewRule: true });
  }

  handleOpenEditAppliedToModal(policy: FirewallPolicy): void {
    this.editAppliedToModalState.set({ isOpen: true, policy });
  }

  handleOpenEditServicesModal(rule: FirewallRule, policyId: string): void {
    this.editServicesModalState.set({ isOpen: true, rule, policyId });
  }

  handleOpenEditRuleAppliedToModal(rule: FirewallRule, policy: FirewallPolicy): void {
    this.editRuleAppliedToModalState.set({ isOpen: true, rule, policy });
  }

  // --- Modal Save/Close Handlers ---

  handleCloseViewMembersModal(): void {
    this.isViewMembersModalOpen.set(false);
    const source = this.modalSource();
    if (source === 'sourceDest') {
        this.editSourceDestModalState.update(s => ({ ...s, isOpen: true }));
    } else if (source === 'appliedTo') {
        this.editAppliedToModalState.update(s => ({ ...s, isOpen: true }));
    } else if (source === 'ruleAppliedTo') {
        this.editRuleAppliedToModalState.update(s => ({ ...s, isOpen: true }));
    }
    this.modalSource.set(null);
  }

  handleSaveSourceDest(newValue: string): void {
    const state = this.editSourceDestModalState();
    if (!state.field) return;

    if (state.isNewRule) {
      this.newRuleForm.update(form => ({ ...form, [state.field!]: newValue }));
    } else if (state.rule && state.policyId) {
      this.handleRuleUpdate(state.policyId, state.rule.id, state.field, newValue);
    }
    this.editSourceDestModalState.set({ isOpen: false, rule: null, policyId: null, field: null });
  }

  handleSaveAppliedTo(data: { policyId: string, newAppliedTo: string }): void {
    this.handlePolicyUpdate(data.policyId, 'appliedTo', data.newAppliedTo);
    this.editAppliedToModalState.set({ isOpen: false, policy: null });
  }

  handleSaveServices(newServices: Service[]): void {
    const state = this.editServicesModalState();
    if (state.rule && state.policyId) {
        this.handleRuleUpdate(state.policyId, state.rule.id, 'services', newServices);
    }
    this.editServicesModalState.set({ isOpen: false, rule: null, policyId: null });
  }

  handleSaveRuleAppliedTo(data: { policyId: string; ruleId: string; newAppliedTo: string }): void {
    this.handleRuleUpdate(data.policyId, data.ruleId, 'appliedTo', data.newAppliedTo);
    this.editRuleAppliedToModalState.set({ isOpen: false, rule: null, policy: null });
  }

  handleAddNewGroup(newGroup: SelectableGroup): void {
    this.availableGroups.update(prev => [newGroup, ...prev]);
  }

}

import { ChangeDetectionStrategy, Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router, RouterModule } from '@angular/router';
import { IconComponent } from '../../../../components/icon/icon.component';
import { FirewallPolicy, FirewallRule, GroupData, SelectableGroup, Service } from '../../types';
import { mockAvailableGroupsForSelection, mockAvailableServices, mockGroupData } from '../../mock-data';
import { MOCK_IDS_IPS_PROFILES_DATA } from '../../../ids-ips-malware-prevention/mock-data';

import { EditSourceDestModalComponent } from '../../components/edit-source-dest-modal/edit-source-dest-modal.component';
import { EditServicesModalComponent } from '../../components/edit-services-modal/edit-services-modal.component';
import { EditProfilesModalComponent } from '../../../gateway-firewall/components/edit-profiles-modal/edit-profiles-modal.component';
import { EditRuleAppliedToModalComponent } from '../../components/edit-rule-applied-to-modal/edit-rule-applied-to-modal.component';
import { ViewMembersModalComponent } from '../../components/view-members-modal/view-members-modal.component';
import { RelatedGroupsModalComponent } from '../../components/related-groups-modal/related-groups-modal.component';

@Component({
  selector: 'app-add-dfw-policy',
  standalone: true,
  imports: [
    CommonModule,
    FormsModule,
    RouterModule,
    IconComponent,
    EditSourceDestModalComponent,
    EditServicesModalComponent,
    EditProfilesModalComponent,
    EditRuleAppliedToModalComponent,
    ViewMembersModalComponent,
    RelatedGroupsModalComponent
  ],
  templateUrl: './add-dfw-policy.component.html',
  styleUrls: ['./add-dfw-policy.component.css'],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class AddDfwPolicyComponent {
  private router = inject(Router);

  policyName = signal('');
  rules = signal<Partial<FirewallRule>[]>([]);

  // Modal states
  editSourceDestModalState = signal<{ isOpen: boolean; rule: Partial<FirewallRule> | null; field: 'sources' | 'destinations' | null; ruleIndex: number | null }>({ isOpen: false, rule: null, field: null, ruleIndex: null });
  editServicesModalState = signal<{ isOpen: boolean; rule: Partial<FirewallRule> | null; ruleIndex: number | null }>({ isOpen: false, rule: null, ruleIndex: null });
  editProfilesModalState = signal<{ isOpen: boolean; rule: Partial<FirewallRule> | null; ruleIndex: number | null }>({ isOpen: false, rule: null, ruleIndex: null });
  editAppliedToModalState = signal<{ isOpen: boolean; rule: Partial<FirewallRule> | null; ruleIndex: number | null }>({ isOpen: false, rule: null, ruleIndex: null });

  isViewMembersModalOpen = signal(false);
  viewingGroup = signal<GroupData | null>(null);
  isRelatedGroupsModalOpen = signal(false);
  viewingRelatedGroup = signal<SelectableGroup | null>(null);

  // Data for modals
  availableGroups = signal<SelectableGroup[]>(mockAvailableGroupsForSelection);
  availableServices = signal<Service[]>(mockAvailableServices);
  availableProfiles = signal<string[]>(['None', ...MOCK_IDS_IPS_PROFILES_DATA.map(p => p.name)]);

  newPolicyName = computed(() => this.policyName() || 'New Policy');

  addRule() {
    const newRule: Partial<FirewallRule> = {
      id: `new-rule-${this.rules().length}`,
      name: `New Rule ${this.rules().length + 1}`,
      sources: 'Any',
      destinations: 'Any',
      services: [{ name: 'Any', icon: 'fas fa-asterisk' }],
      contextProfiles: 'None',
      appliedTo: 'DFW',
      action: 'Allow',
      enabled: true,
      status: 'Success'
    };
    this.rules.update(rules => [...rules, newRule]);
  }

  removeRule(ruleId: string) {
    this.rules.update(rules => rules.filter(r => r.id !== ruleId));
  }

  getServiceNames(services: Service[] | undefined): string {
    if (!services) return '';
    return services.map(s => s.name).join(', ');
  }

  // --- Modal Openers ---
  openEditSourceDestModal(rule: Partial<FirewallRule>, ruleIndex: number, field: 'sources' | 'destinations') {
    this.editSourceDestModalState.set({ isOpen: true, rule, field, ruleIndex });
  }

  openEditServicesModal(rule: Partial<FirewallRule>, ruleIndex: number) {
    this.editServicesModalState.set({ isOpen: true, rule, ruleIndex });
  }

  openEditProfilesModal(rule: Partial<FirewallRule>, ruleIndex: number) {
    this.editProfilesModalState.set({ isOpen: true, rule, ruleIndex });
  }

  openEditAppliedToModal(rule: Partial<FirewallRule>, ruleIndex: number) {
    this.editAppliedToModalState.set({ isOpen: true, rule, ruleIndex });
  }

  handleOpenViewMembersModal(groupName: string): void {
    const groupData = mockGroupData[groupName];
    if (groupData) {
      this.viewingGroup.set(groupData);
      this.isViewMembersModalOpen.set(true);
    }
  }

  handleOpenRelatedGroupsModal(group: SelectableGroup): void {
    this.viewingRelatedGroup.set(group);
    this.isRelatedGroupsModalOpen.set(true);
  }

  handleCloseViewMembersModal() {
    this.isViewMembersModalOpen.set(false);
  }

  handleAddNewGroup(newGroup: SelectableGroup) {
      this.availableGroups.update(groups => [newGroup, ...groups]);
  }

  // --- Modal Savers ---
  handleSaveSourceDest(value: string) {
    const { field, ruleIndex } = this.editSourceDestModalState();
    if (field !== null && ruleIndex !== null) {
      this.rules.update(rules => {
        const newRules = [...rules];
        newRules[ruleIndex] = { ...newRules[ruleIndex], [field]: value };
        return newRules;
      });
    }
    this.editSourceDestModalState.set({ isOpen: false, rule: null, field: null, ruleIndex: null });
  }

  handleSaveServices(services: Service[]) {
    const { ruleIndex } = this.editServicesModalState();
    if (ruleIndex !== null) {
      this.rules.update(rules => {
        const newRules = [...rules];
        newRules[ruleIndex] = { ...newRules[ruleIndex], services };
        return newRules;
      });
    }
    this.editServicesModalState.set({ isOpen: false, rule: null, ruleIndex: null });
  }

  handleSaveProfile(profile: string) {
      const { ruleIndex } = this.editProfilesModalState();
      if (ruleIndex !== null) {
          this.rules.update(rules => {
              const newRules = [...rules];
              newRules[ruleIndex] = { ...newRules[ruleIndex], contextProfiles: profile };
              return newRules;
          });
      }
      this.editProfilesModalState.set({ isOpen: false, rule: null, ruleIndex: null });
  }

  handleSaveAppliedTo(data: { policyId: string; ruleId: string; newAppliedTo: string }) {
      const { ruleIndex } = this.editAppliedToModalState();
      if (ruleIndex !== null) {
          this.rules.update(rules => {
              const newRules = [...rules];
              newRules[ruleIndex] = { ...newRules[ruleIndex], appliedTo: data.newAppliedTo };
              return newRules;
          });
      }
      this.editAppliedToModalState.set({ isOpen: false, rule: null, ruleIndex: null });
  }

  save() {
    console.log("Saving policy", this.policyName(), this.rules());
    // In real app, we would use a service to save this
    // For now, just navigate back
    this.router.navigate(['/app/cloud-edge/security/distributed-firewall']);
  }

  cancel() {
      this.router.navigate(['/app/cloud-edge/security/distributed-firewall']);
  }
}

