import { ChangeDetectionStrategy, Component, computed, signal, effect, ElementRef, viewChild } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { IconComponent } from '../../components/icon/icon.component';
import { ToggleSwitchComponent } from './components/toggle-switch/toggle-switch.component';
import { ViewMembersModalComponent } from './components/view-members-modal/view-members-modal.component';
import { EditSourceDestModalComponent } from './components/edit-source-dest-modal/edit-source-dest-modal.component';
import { EditAppliedToModalComponent } from './components/edit-applied-to-modal/edit-applied-to-modal.component';
import { RelatedGroupsModalComponent } from './components/related-groups-modal/related-groups-modal.component';
import { AddPolicyModalComponent } from './components/add-policy-modal/add-policy-modal.component';
import { EditServicesModalComponent } from './components/edit-services-modal/edit-services-modal.component';
import { EditRuleAppliedToModalComponent } from './components/edit-rule-applied-to-modal/edit-rule-applied-to-modal.component';
import { AppliedToDisplayComponent } from './components/applied-to-display/applied-to-display.component';
import { FirewallPolicy, FirewallRule, GroupData, SelectableGroup, Service } from './types';
import { mockPoliciesData, mockGroupData, mockAvailableGroupsForSelection, mockAvailableServices } from './mock-data';
import { AdvancedDeleteConfirmationModalComponent } from '../../components/advanced-delete-confirmation-modal/advanced-delete-confirmation-modal.component';

@Component({
  selector: 'app-distributed-firewall',
  templateUrl: './distributed-firewall.component.html',
  styleUrls: ['./distributed-firewall.component.css'],
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    CommonModule,
    FormsModule,
    IconComponent,
    ToggleSwitchComponent,
    AdvancedDeleteConfirmationModalComponent,
    ViewMembersModalComponent,
    EditSourceDestModalComponent,
    EditAppliedToModalComponent,
    RelatedGroupsModalComponent,
    AddPolicyModalComponent,
    EditServicesModalComponent,
    EditRuleAppliedToModalComponent,
    AppliedToDisplayComponent,
  ],
  host: {
    '(document:mousedown)': 'onGlobalClick($event)',
  },
})
export class DistributedFirewallComponent {
  // Main state
  policies = signal<FirewallPolicy[]>(mockPoliciesData);
  selectedItems = signal<string[]>([]);

  // Available data for modals
  availableGroups = signal<SelectableGroup[]>(mockAvailableGroupsForSelection);
  availableServices = signal<{ name: string; icon: string }[]>(mockAvailableServices);

  // New rule state
  addingRuleToPolicyId = signal<string | null>(null);
  newRuleForm = signal(this.getInitialNewRuleState());

  // Modal states
  isDeleteModalOpen = signal(false);
  isViewMembersModalOpen = signal(false);
  viewingGroup = signal<GroupData | null>(null);
  isAddPolicyModalOpen = signal(false);
  isRelatedGroupsModalOpen = signal(false);
  viewingRelatedGroup = signal<SelectableGroup | null>(null);

  editSourceDestModalState = signal<{ isOpen: boolean; rule: FirewallRule | null; policyId: string | null; field: 'sources' | 'destinations' | null; isNewRule?: boolean }>({ isOpen: false, rule: null, policyId: null, field: null });
  editAppliedToModalState = signal<{ isOpen: boolean; policy: FirewallPolicy | null }>({ isOpen: false, policy: null });
  editServicesModalState = signal<{ isOpen: boolean; rule: FirewallRule | null; policyId: string | null }>({ isOpen: false, rule: null, policyId: null });
  editRuleAppliedToModalState = signal<{ isOpen: boolean; rule: FirewallRule | null; policy: FirewallPolicy | null }>({ isOpen: false, rule: null, policy: null });
  modalSource = signal<'sourceDest' | 'appliedTo' | 'ruleAppliedTo' | null>(null);

  isActionsMenuOpen = signal(false);
  actionsMenuRef = viewChild<ElementRef>('actionsMenuRef');
  actionsButtonRef = viewChild<ElementRef>('actionsButtonRef');

  // Computed properties
  isSelectionEmpty = computed(() => this.selectedItems().length === 0);
  isSingleSelection = computed(() => this.selectedItems().length === 1);
  isSinglePolicySelected = computed(() => {
    if (!this.isSingleSelection()) return false;
    const selectedId = this.selectedItems()[0];
    return this.policies().some(p => p.id === selectedId);
  });

  constructor() {
    effect(() => {
      // Auto-expand policy when adding a new rule to it
      const policyId = this.addingRuleToPolicyId();
      if (policyId) {
        const policy = this.policies().find(p => p.id === policyId);
        if (policy && !policy.isExpanded) {
          this.togglePolicy(policyId);
        }
      }
    });
  }

  onGlobalClick(event: MouseEvent): void {
      if (
          this.isActionsMenuOpen() &&
          this.actionsMenuRef() && !this.actionsMenuRef()!.nativeElement.contains(event.target as Node) &&
          this.actionsButtonRef() && !this.actionsButtonRef()!.nativeElement.contains(event.target as Node)
      ) {
          this.isActionsMenuOpen.set(false);
      }
  }

  getInitialNewRuleState() {
    return {
      name: '',
      sources: 'Any',
      destinations: 'Any',
      services: [{ name: 'Any', icon: 'fas fa-asterisk' }],
      action: 'Allow' as 'Allow' | 'Deny' | 'Drop',
      enabled: true,
      contextProfiles: 'None',
      appliedTo: 'DFW'
    };
  }

  // --- Main Actions ---

  handleAddPolicyClick(): void {
    this.isAddPolicyModalOpen.set(true);
  }

  handleSaveNewPolicy(policyName: string): void {
    const newPolicy: FirewallPolicy = {
      id: `policy-${Date.now()}`,
      name: policyName,
      policyId: '(0)',
      appliedTo: 'DFW',
      status: 'Success',
      rules: [],
      isExpanded: true,
    };
    this.policies.update(prev => [newPolicy, ...prev]);
    this.selectedItems.set([newPolicy.id]);
    this.addingRuleToPolicyId.set(newPolicy.id);
    this.newRuleForm.set({ ...this.getInitialNewRuleState(), name: `New Rule in ${policyName}` });
    this.isAddPolicyModalOpen.set(false);
  }

  handleAddRuleClick(): void {
    if (this.isSinglePolicySelected()) {
      const policyId = this.selectedItems()[0];
      this.addingRuleToPolicyId.set(policyId);
      const policyName = this.policies().find(p => p.id === policyId)?.name || '';
      this.newRuleForm.set({ ...this.getInitialNewRuleState(), name: `New Rule in ${policyName}` });
    }
  }

  handleCancelNewRule(): void {
    this.addingRuleToPolicyId.set(null);
  }

  handleSaveNewRule(): void {
    const policyId = this.addingRuleToPolicyId();
    const formState = this.newRuleForm();
    if (!policyId || !formState.name.trim()) return;

    const newRule: FirewallRule = {
      id: `rule-${Date.now()}`,
      ruleId: String(Math.floor(Math.random() * 100) + 10),
      ...formState,
      status: 'Success'
    };

    this.policies.update(prev => prev.map(p => 
      p.id === policyId ? { ...p, rules: [newRule, ...p.rules] } : p
    ));
    this.handleCancelNewRule();
  }

  handleDeleteClick(): void {
    if (this.isSelectionEmpty()) return;
    this.isDeleteModalOpen.set(true);
  }

  handleConfirmDelete(): void {
    const selected = this.selectedItems();
    this.policies.update(prev => {
        const remainingPolicies = prev.filter(p => !selected.includes(p.id));
        return remainingPolicies.map(p => ({
            ...p,
            rules: p.rules.filter(r => !selected.includes(r.id))
        }));
    });
    this.selectedItems.set([]);
    this.isDeleteModalOpen.set(false);
  }

  // --- Table Interactions ---

  togglePolicy(policyId: string): void {
    this.policies.update(ps => ps.map(p => p.id === policyId ? { ...p, isExpanded: !p.isExpanded } : p));
  }

  handleSelect(id: string, event: Event): void {
    const isChecked = (event.target as HTMLInputElement).checked;
    this.selectedItems.update(prev => 
      isChecked ? [...prev, id] : prev.filter(i => i !== id)
    );
  }

  handleRuleUpdate(policyId: string, ruleId: string, field: keyof Omit<FirewallRule, 'id' | 'ruleId'>, value: any): void {
    this.policies.update(ps => ps.map(p => {
        if (p.id === policyId) {
            return { ...p, rules: p.rules.map(r => r.id === ruleId ? { ...r, [field]: value } : r) };
        }
        return p;
    }));
  }

  handlePolicyUpdate(policyId: string, field: keyof Omit<FirewallPolicy, 'id' | 'rules'>, value: any): void {
      this.policies.update(ps => ps.map(p => p.id === policyId ? { ...p, [field]: value } : p));
  }

  getServiceNames(services: Service[]): string {
    return services.map(s => s.name).join(', ');
  }

  handleNewRuleEnabledChange(enabled: boolean): void {
    this.newRuleForm.update(form => ({ ...form, enabled }));
  }

  // --- Modal Opening ---

  handleOpenViewMembersModal(groupName: string, source: 'sourceDest' | 'appliedTo' | 'ruleAppliedTo'): void {
    const groupData = mockGroupData[groupName];
    if (groupData) {
      this.viewingGroup.set(groupData);
      if (source === 'sourceDest') {
        this.editSourceDestModalState.update(s => ({ ...s, isOpen: false }));
      } else if (source === 'appliedTo') {
        this.editAppliedToModalState.update(s => ({ ...s, isOpen: false }));
      } else { // ruleAppliedTo
        this.editRuleAppliedToModalState.update(s => ({ ...s, isOpen: false }));
      }
      this.isViewMembersModalOpen.set(true);
      this.modalSource.set(source);
    }
  }

  handleOpenRelatedGroupsModal(group: SelectableGroup): void {
    this.viewingRelatedGroup.set(group);
    this.isRelatedGroupsModalOpen.set(true);
  }

  handleOpenEditSourceDestModal(rule: FirewallRule, policyId: string, field: 'sources' | 'destinations'): void {
    this.editSourceDestModalState.set({ isOpen: true, rule, policyId, field });
  }

  handleOpenEditSourceDestModalForNewRule(field: 'sources' | 'destinations'): void {
    const policyId = this.addingRuleToPolicyId();
    if (!policyId) return;
    const formState = this.newRuleForm();
    const tempRule: FirewallRule = { id: 'new-rule', ruleId: 'new', ...formState, status: 'Success' };
    this.editSourceDestModalState.set({ isOpen: true, rule: tempRule, policyId, field, isNewRule: true });
  }

  handleOpenEditAppliedToModal(policy: FirewallPolicy): void {
    this.editAppliedToModalState.set({ isOpen: true, policy });
  }

  handleOpenEditServicesModal(rule: FirewallRule, policyId: string): void {
    this.editServicesModalState.set({ isOpen: true, rule, policyId });
  }

  handleOpenEditRuleAppliedToModal(rule: FirewallRule, policy: FirewallPolicy): void {
    this.editRuleAppliedToModalState.set({ isOpen: true, rule, policy });
  }

  // --- Modal Save/Close Handlers ---

  handleCloseViewMembersModal(): void {
    this.isViewMembersModalOpen.set(false);
    const source = this.modalSource();
    if (source === 'sourceDest') {
        this.editSourceDestModalState.update(s => ({ ...s, isOpen: true }));
    } else if (source === 'appliedTo') {
        this.editAppliedToModalState.update(s => ({ ...s, isOpen: true }));
    } else if (source === 'ruleAppliedTo') {
        this.editRuleAppliedToModalState.update(s => ({ ...s, isOpen: true }));
    }
    this.modalSource.set(null);
  }

  handleSaveSourceDest(newValue: string): void {
    const state = this.editSourceDestModalState();
    if (!state.field) return;

    if (state.isNewRule) {
      this.newRuleForm.update(form => ({ ...form, [state.field!]: newValue }));
    } else if (state.rule && state.policyId) {
      this.handleRuleUpdate(state.policyId, state.rule.id, state.field, newValue);
    }
    this.editSourceDestModalState.set({ isOpen: false, rule: null, policyId: null, field: null });
  }

  handleSaveAppliedTo(data: { policyId: string, newAppliedTo: string }): void {
    this.handlePolicyUpdate(data.policyId, 'appliedTo', data.newAppliedTo);
    this.editAppliedToModalState.set({ isOpen: false, policy: null });
  }

  handleSaveServices(newServices: Service[]): void {
    const state = this.editServicesModalState();
    if (state.rule && state.policyId) {
        this.handleRuleUpdate(state.policyId, state.rule.id, 'services', newServices);
    }
    this.editServicesModalState.set({ isOpen: false, rule: null, policyId: null });
  }

  handleSaveRuleAppliedTo(data: { policyId: string; ruleId: string; newAppliedTo: string }): void {
    this.handleRuleUpdate(data.policyId, data.ruleId, 'appliedTo', data.newAppliedTo);
    this.editRuleAppliedToModalState.set({ isOpen: false, rule: null, policy: null });
  }

  handleAddNewGroup(newGroup: SelectableGroup): void {
    this.availableGroups.update(prev => [newGroup, ...prev]);
  }

}

import { Injectable, signal } from '@angular/core';
import { VirtualMachine, VIRTUAL_MACHINES_DATA } from '../mock-data';

@Injectable({
  providedIn: 'root',
})
export class VirtualMachineService {
  private initialVms = VIRTUAL_MACHINES_DATA.filter(vm => vm.id !== 'vm-05');
  private initialRecycledVms = VIRTUAL_MACHINES_DATA.filter(vm => vm.id === 'vm-05').map(vm => ({...vm, deletedAt: new Date(Date.now() - 12 * 60 * 60 * 1000).toISOString()})); // 12 hours ago

  private virtualMachinesState = signal<VirtualMachine[]>(this.initialVms);
  private recycledVirtualMachinesState = signal<VirtualMachine[]>(this.initialRecycledVms);

  virtualMachines = this.virtualMachinesState.asReadonly();
  recycledVirtualMachines = this.recycledVirtualMachinesState.asReadonly();

  addVm(newVmConfig: { 
    name: string; 
    os: 'windows' | 'ubuntu' | 'linux'; 
    cores: number; 
    memory: number; 
    storage: number; 
    description: string; 
  }) {
    const newVm: VirtualMachine = {
      id: `vm-${Date.now()}`,
      name: newVmConfig.name,
      os: newVmConfig.os,
      cores: newVmConfig.cores,
      memory: newVmConfig.memory,
      storage: newVmConfig.storage,
      description: newVmConfig.description,
      nicCount: 1, // default
      ipAddress: `192.168.1.${Math.floor(Math.random() * 254) + 1}`, // random IP for demo
      reservationName: null, // from marketplace, so no reservation initially
      creationDate: new Date().toISOString().split('T')[0],
      status: 'running'
    };

    this.virtualMachinesState.update(vms => [newVm, ...vms]);
  }

  updateVmStatus(vmId: string, status: 'running' | 'stopped' | 'suspended'): void {
    this.virtualMachinesState.update(vms =>
      vms.map(vm => (vm.id === vmId ? { ...vm, status } : vm))
    );
  }

  deleteVm(vmId: string): void {
    const vmToDelete = this.virtualMachinesState().find(vm => vm.id === vmId);
    if (!vmToDelete) return;

    const vmToRecycle: VirtualMachine = {
      ...vmToDelete,
      status: vmToDelete.status === 'running' ? 'stopped' : vmToDelete.status,
      deletedAt: new Date().toISOString(),
    };

    // Move to recycled
    this.recycledVirtualMachinesState.update(recycled => [
      ...recycled,
      vmToRecycle,
    ]);

    // Remove from active
    this.virtualMachinesState.update(vms => vms.filter(vm => vm.id !== vmId));
  }

  recoverVm(vmId: string): void {
    const vmToRecover = this.recycledVirtualMachinesState().find(vm => vm.id === vmId);
    if (!vmToRecover) return;

    this.recycledVirtualMachinesState.update(recycled => recycled.filter(vm => vm.id !== vmId));

    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const { deletedAt, ...restoredVm } = vmToRecover;
    this.virtualMachinesState.update(vms => [...vms, restoredVm]);
  }

  permanentlyDeleteVm(vmId: string): void {
    this.recycledVirtualMachinesState.update(recycled => recycled.filter(vm => vm.id !== vmId));
  }
}

import { ChangeDetectionStrategy, Component, ElementRef, signal, viewChild, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { IconComponent } from '../../components/icon/icon.component';
import { VmCardViewComponent } from './components/vm-card-view/vm-card-view.component';
import { VmTableViewComponent } from './components/vm-table-view/vm-table-view.component';
import { VirtualMachine } from './mock-data';
import { FilterPanelComponent } from '../../components/filter-panel/filter-panel.component';
import { ConfirmationModalComponent } from '../../components/confirmation-modal/confirmation-modal.component';
import { VirtualMachineService } from './services/virtual-machine.service';
import { AdvancedDeleteConfirmationModalComponent } from '../../components/advanced-delete-confirmation-modal/advanced-delete-confirmation-modal.component';

interface VmFilterState {
  status: 'all' | 'running' | 'stopped' | 'suspended';
  os: 'all' | 'windows' | 'ubuntu' | 'linux';
  hasReservation: boolean;
}

@Component({
  selector: 'app-virtual-machines',
  templateUrl: './virtual-machines.component.html',
  styleUrls: ['./virtual-machines.component.css'],
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule, IconComponent, VmCardViewComponent, VmTableViewComponent, RouterModule, FormsModule, FilterPanelComponent, ConfirmationModalComponent, AdvancedDeleteConfirmationModalComponent],
  host: {
    '(document:mousedown)': 'onGlobalClick($event)',
  },
})
export class VirtualMachinesComponent {
  private virtualMachineService = inject(VirtualMachineService);

  viewMode = signal<'card' | 'table'>('card');
  allVirtualMachines = this.virtualMachineService.virtualMachines;

  isExportMenuOpen = signal(false);
  exportButtonRef = viewChild<ElementRef>('exportButtonRef');
  exportMenuRef = viewChild<ElementRef>('exportMenuRef');

  // --- Filter State ---
  searchTerm = signal('');
  isFilterPanelOpen = signal(false);

  private readonly defaultFilters: VmFilterState = {
    status: 'all',
    os: 'all',
    hasReservation: false,
  };

  filters = signal<VmFilterState>({ ...this.defaultFilters });
  tempFilters = signal<VmFilterState>({ ...this.defaultFilters });

  public readonly vmStatuses: VmFilterState['status'][] = ['all', 'running', 'stopped', 'suspended'];
  public readonly vmOses: VmFilterState['os'][] = ['all', 'windows', 'ubuntu', 'linux'];

  filteredVirtualMachines = computed(() => {
    const currentFilters = this.filters();
    const term = this.searchTerm().toLowerCase();

    let filtered = this.allVirtualMachines();

    // 1. Filter by search term
    if (term) {
      filtered = filtered.filter(vm => 
        vm.name.toLowerCase().includes(term) ||
        (vm.description && vm.description.toLowerCase().includes(term)) ||
        vm.ipAddress.toLowerCase().includes(term)
      );
    }

    // 2. Apply advanced filters
    return filtered.filter(vm => {
      const statusMatch = currentFilters.status === 'all' || vm.status === currentFilters.status;
      const osMatch = currentFilters.os === 'all' || vm.os === currentFilters.os;
      const reservationMatch = !currentFilters.hasReservation || vm.reservationName !== null;

      return statusMatch && osMatch && reservationMatch;
    });
  });

  activeFilterCount = computed(() => {
    const { status, os, hasReservation } = this.filters();
    let count = 0;
    if (status !== 'all') count++;
    if (os !== 'all') count++;
    if (hasReservation) count++;
    return count;
  });

  // --- Confirmation Modal State (Non-delete actions) ---
  isConfirmModalOpen = signal(false);
  confirmModalConfig = signal({
      title: '',
      message: '',
      confirmButtonText: '',
      confirmButtonClass: '',
      iconName: '',
      iconClass: ''
  });
  selectedVmForAction = signal<VirtualMachine | null>(null);
  actionToConfirm = signal<'connect' | 'powerOff' | 'restart' | null>(null);

  // --- Delete Modal State ---
  isDeleteModalOpen = signal(false);
  vmToDelete = signal<VirtualMachine | null>(null);

  deleteModalMessage = computed(() => {
    const vmName = this.vmToDelete()?.name;
    if (!vmName) return '';
    return `
        <p class="mb-2">If this VM is running, it will be powered off before being moved to the Recycle Bin.</p>
        <p>You can't get your deleted virtual machine data (OS, hard disks,...) after 24 hour from now.</p>
        <p class="mt-2">You could recover deleted virtual machine within 24 hour from recycle bin.</p>
        <p class="mt-4">To proceed, please type the name of the Virtual Machine (<strong class="text-gray-900 dark:text-gray-100">${vmName}</strong>) below.</p>
    `;
  });

  // --- Filter Panel Logic ---
  openFilterPanel(): void {
    this.tempFilters.set({ ...this.filters() });
    this.isFilterPanelOpen.set(true);
  }

  closeFilterPanel(): void {
    this.isFilterPanelOpen.set(false);
  }

  applyFilters(): void {
    this.filters.set(this.tempFilters());
    this.closeFilterPanel();
  }

  clearFilters(): void {
    this.filters.set({ ...this.defaultFilters });
    this.tempFilters.set({ ...this.defaultFilters });
    this.closeFilterPanel();
  }

  setViewMode(mode: 'card' | 'table'): void {
    this.viewMode.set(mode);
  }

  onGlobalClick(event: MouseEvent): void {
    if (
      this.isExportMenuOpen() &&
      this.exportButtonRef()?.nativeElement &&
      !this.exportButtonRef()!.nativeElement.contains(event.target as Node) &&
      this.exportMenuRef()?.nativeElement &&
      !this.exportMenuRef()!.nativeElement.contains(event.target as Node)
    ) {
      this.isExportMenuOpen.set(false);
    }
  }

  toggleExportMenu(): void {
    this.isExportMenuOpen.update(v => !v);
  }

  private downloadFile(data: string, filename: string, type: string): void {
    const blob = new Blob([data], { type });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    window.URL.revokeObjectURL(url);
    this.isExportMenuOpen.set(false);
  }

  exportAsCsv(): void {
    const vms = this.filteredVirtualMachines();
    const headers = ['Name', 'OS', 'Status', 'IP Address', 'Creation Date', 'Cores', 'Memory (GB)', 'Storage (GB)'];
    const selectedData = vms.map(vm => ({
      name: vm.name,
      os: vm.os,
      status: vm.status,
      ipAddress: vm.ipAddress,
      creationDate: vm.creationDate,
      cores: vm.cores,
      memory: vm.memory,
      storage: vm.storage,
    }));

    let csvContent = headers.join(',') + '\r\n';
    selectedData.forEach(row => {
        const values = Object.values(row).map(value => `"${value}"`).join(',');
        csvContent += values + '\r\n';
    });
    this.downloadFile(csvContent, 'virtual_machines.csv', 'text/csv');
  }

  exportAsJson(): void {
    const vms = this.filteredVirtualMachines();
    const jsonContent = JSON.stringify(vms, null, 2);
    this.downloadFile(jsonContent, 'virtual_machines.json', 'application/json');
  }

  handleVmAction(event: { action: 'connect' | 'powerOff' | 'restart' | 'delete'; vm: VirtualMachine }): void {
    const { action, vm } = event;

    if (action === 'delete') {
      this.vmToDelete.set(vm);
      this.isDeleteModalOpen.set(true);
      return;
    }

    this.selectedVmForAction.set(vm);
    this.actionToConfirm.set(action);
    let config;

    switch (action) {
      case 'connect':
        config = {
          title: `Connect to ${vm.name}`,
          message: `You are about to connect to the web console for <strong>${vm.name}</strong>. Proceed?`,
          confirmButtonText: 'Connect',
          confirmButtonClass: 'bg-[#679a41] hover:bg-[#537d34]',
          iconName: 'fas fa-terminal',
          iconClass: 'text-gray-500',
        };
        break;
      case 'powerOff':
        config = {
          title: `Power Off ${vm.name}`,
          message: `Are you sure you want to power off <strong>${vm.name}</strong>? This is equivalent to pulling the power cord.`,
          confirmButtonText: 'Power Off',
          confirmButtonClass: 'bg-red-600 hover:bg-red-700',
          iconName: 'fas fa-power-off',
          iconClass: 'text-red-500',
        };
        break;
      case 'restart':
        config = {
          title: `Restart ${vm.name}`,
          message: `Are you sure you want to restart <strong>${vm.name}</strong>? This will abruptly stop and then start the virtual machine.`,
          confirmButtonText: 'Restart',
          confirmButtonClass: 'bg-orange-500 hover:bg-orange-600',
          iconName: 'fas fa-sync-alt',
          iconClass: 'text-orange-500',
        };
        break;
    }

    this.confirmModalConfig.set(config);
    this.isConfirmModalOpen.set(true);
  }

  onCloseConfirmModal(): void {
    this.isConfirmModalOpen.set(false);
    this.selectedVmForAction.set(null);
    this.actionToConfirm.set(null);
  }

  onConfirmAction(): void {
      const vm = this.selectedVmForAction();
      const action = this.actionToConfirm();
      if (vm && action) {
          console.log(`Action '${action}' confirmed for VM: ${vm.name}`);
          if (action === 'powerOff') {
            this.virtualMachineService.updateVmStatus(vm.id, 'stopped');
          } else if (action === 'restart') {
            this.virtualMachineService.updateVmStatus(vm.id, 'stopped');
            setTimeout(() => this.virtualMachineService.updateVmStatus(vm.id, 'running'), 1000);
          }
      }
      this.onCloseConfirmModal();
  }

  handleConfirmDelete(): void {
    const vm = this.vmToDelete();
    if (vm) {
      this.virtualMachineService.deleteVm(vm.id);
    }
    this.isDeleteModalOpen.set(false);
    this.vmToDelete.set(null);
  }
}

import { ChangeDetectionStrategy, Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { IconComponent } from '../../../../components/icon/icon.component';
import { ToggleSwitchComponent } from '../../../distributed-firewall/components/toggle-switch/toggle-switch.component';
import { IdsIpsPolicy, IdsIpsRule } from '../../types';
import { MOCK_IDS_IPS_POLICIES_DATA, MOCK_IDS_IPS_PROFILES_DATA } from '../../mock-data';
import { DeleteConfirmationModalComponent } from '../../../distributed-firewall/components/delete-confirmation-modal/delete-confirmation-modal.component';
import { EditableNameComponent } from '../../../gateway-firewall/components/editable-name/editable-name.component';
import { EditSourceDestModalComponent } from '../../../distributed-firewall/components/edit-source-dest-modal/edit-source-dest-modal.component';
import { EditServicesModalComponent } from '../../../distributed-firewall/components/edit-services-modal/edit-services-modal.component';
import { EditProfilesModalComponent } from '../../../gateway-firewall/components/edit-profiles-modal/edit-profiles-modal.component';
import { ViewMembersModalComponent } from '../../../distributed-firewall/components/view-members-modal/view-members-modal.component';
import { RelatedGroupsModalComponent } from '../../../distributed-firewall/components/related-groups-modal/related-groups-modal.component';
import { GroupData, SelectableGroup, Service, FirewallRule } from '../../../distributed-firewall/types';
import { mockAvailableGroupsForSelection, mockAvailableServices, mockGroupData } from '../../../distributed-firewall/mock-data';
import { AddPolicyModalComponent } from '../../../distributed-firewall/components/add-policy-modal/add-policy-modal.component';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-rules-view',
  templateUrl: './rules-view.component.html',
  styleUrls: ['./rules-view.component.css'],
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    CommonModule,
    IconComponent,
    ToggleSwitchComponent,
    DeleteConfirmationModalComponent,
    EditableNameComponent,
    EditSourceDestModalComponent,
    EditServicesModalComponent,
    EditProfilesModalComponent,
    ViewMembersModalComponent,
    RelatedGroupsModalComponent,
    AddPolicyModalComponent,
    FormsModule,
  ],
})
export class RulesViewComponent {
  policies = signal<IdsIpsPolicy[]>(MOCK_IDS_IPS_POLICIES_DATA);
  selectedItems = signal<string[]>([]);
  isDeleteModalOpen = signal(false);

  // Modal states
  editSourceDestModalState = signal<{ isOpen: boolean; rule: FirewallRule | null; policyId: string | null; field: 'sources' | 'destinations' | null; isNewRule?: boolean }>({ isOpen: false, rule: null, policyId: null, field: null });
  editServicesModalState = signal<{ isOpen: boolean; rule: IdsIpsRule | null; policyId: string | null; isNewRule?: boolean }>({ isOpen: false, rule: null, policyId: null });
  editProfilesModalState = signal<{ isOpen: boolean; rule: IdsIpsRule | null; policyId: string | null; isNewRule?: boolean }>({ isOpen: false, rule: null, policyId: null });
  isViewMembersModalOpen = signal(false);
  viewingGroup = signal<GroupData | null>(null);
  isRelatedGroupsModalOpen = signal(false);
  viewingRelatedGroup = signal<SelectableGroup | null>(null);
  isAddPolicyModalOpen = signal(false);

  // New Rule State
  addingRuleToPolicyId = signal<string | null>(null);
  newRuleForm = signal(this.getInitialNewRuleState());

  // Data for modals
  availableGroups = signal<SelectableGroup[]>(mockAvailableGroupsForSelection);
  availableServices = signal<Service[]>(mockAvailableServices);
  availableProfiles = signal<string[]>(['None', ...MOCK_IDS_IPS_PROFILES_DATA.map(p => p.name)]);

  isSelectionEmpty = computed(() => this.selectedItems().length === 0);
  isSingleSelection = computed(() => this.selectedItems().length === 1);
  isSinglePolicySelected = computed(() => {
    const selected = this.selectedItems();
    if (selected.length !== 1) return false;
    return this.policies().some(p => p.id === selected[0]);
  });

  getInitialNewRuleState() {
    return {
      name: '',
      sources: 'Any',
      destinations: 'Any',
      services: [{ name: 'Any', icon: 'fas fa-asterisk' }],
      profile: 'Balanced - Detect & Prevent',
      enabled: true,
    };
  }

  togglePolicy(policyId: string): void {
    this.policies.update(currentPolicies => currentPolicies.map(p =>
      p.id === policyId ? { ...p, isExpanded: !p.isExpanded } : p
    ));
  }

  handleSelect(id: string, isChecked: boolean): void {
    this.selectedItems.update(prev => 
      isChecked ? [...prev, id] : prev.filter(i => i !== id)
    );
  }

  handlePolicyNameSave(policyId: string, newName: string): void {
      this.policies.update(ps => ps.map(p => p.id === policyId ? {...p, name: newName} : p));
  }

  handleRuleNameSave(policyId: string, ruleId: string, newName: string): void {
      this.policies.update(ps => ps.map(p => {
          if (p.id === policyId) {
              return {...p, rules: p.rules.map(r => r.id === ruleId ? {...r, name: newName} : r)}
          }
          return p;
      }));
  }

  handleRuleUpdate(policyId: string, ruleId: string, field: keyof Omit<IdsIpsRule, 'id'>, value: any): void {
    this.policies.update(ps => ps.map(p => {
        if (p.id === policyId) {
            return { ...p, rules: p.rules.map(r => r.id === ruleId ? { ...r, [field]: value } : r) };
        }
        return p;
    }));
  }

  getServiceNames(services: Service[]): string {
    return services.map(s => s.name).join(', ');
  }

  // --- Main Actions ---
  handleAddPolicyClick(): void {
    this.isAddPolicyModalOpen.set(true);
  }

  handleSaveNewPolicy(policyName: string): void {
    const newPolicy: IdsIpsPolicy = {
      id: `policy-${Date.now()}`,
      name: policyName,
      policyId: `(${Math.floor(Math.random() * 10)})`,
      status: 'Success',
      rules: [],
      isExpanded: true,
    };
    this.policies.update(prev => [newPolicy, ...prev]);
    this.selectedItems.set([newPolicy.id]);
    this.addingRuleToPolicyId.set(newPolicy.id);
    this.newRuleForm.set({ ...this.getInitialNewRuleState(), name: `New Rule in ${policyName}` });
    this.isAddPolicyModalOpen.set(false);
  }

  handleAddRuleClick(): void {
    if (this.isSinglePolicySelected()) {
      const policyId = this.selectedItems()[0];
      this.addingRuleToPolicyId.set(policyId);
      const policyName = this.policies().find(p => p.id === policyId)?.name || '';
      this.newRuleForm.set({ ...this.getInitialNewRuleState(), name: `New Rule in ${policyName}` });
    }
  }

  handleCancelNewRule(): void {
    this.addingRuleToPolicyId.set(null);
  }

  handleSaveNewRule(): void {
    const policyId = this.addingRuleToPolicyId();
    const formState = this.newRuleForm();
    if (!policyId || !formState.name.trim()) return;

    const newRule: IdsIpsRule = {
      id: `rule-${Date.now()}`,
      ...formState
    };

    this.policies.update(prev => prev.map(p =>
      p.id === policyId ? { ...p, rules: [newRule, ...p.rules] } : p
    ));
    this.handleCancelNewRule();
  }

  handleDeleteClick(): void {
    if (this.isSelectionEmpty()) return;
    this.isDeleteModalOpen.set(true);
  }

  handleConfirmDelete(): void {
    const selected = this.selectedItems();
    this.policies.update(prev => {
        const remainingPolicies = prev.filter(p => !selected.includes(p.id));
        return remainingPolicies.map(p => ({
            ...p,
            rules: p.rules.filter(r => !selected.includes(r.id))
        }));
    });
    this.selectedItems.set([]);
    this.isDeleteModalOpen.set(false);
  }

  // --- New Rule Form State Handlers ---
  handleNewRuleEnabledChange(enabled: boolean): void {
    this.newRuleForm.update(form => ({...form, enabled}));
  }

  // --- Modal Opening ---
  handleOpenEditSourceDestModal(policyId: string, rule: IdsIpsRule, field: 'sources' | 'destinations'): void {
    const mappedRule: FirewallRule = {
      ...rule,
      ruleId: rule.id, // Placeholder
      contextProfiles: rule.profile,
      appliedTo: 'DFW', // Placeholder
      action: 'Allow', // Placeholder
      status: 'Success'
    };
    this.editSourceDestModalState.set({ isOpen: true, rule: mappedRule, policyId, field });
  }

  handleOpenEditSourceDestModalForNewRule(field: 'sources' | 'destinations'): void {
    const policyId = this.addingRuleToPolicyId();
    if (!policyId) return;
    const formState = this.newRuleForm();
    const tempRule: IdsIpsRule = { id: 'new-rule', ...formState };
    const mappedRule: FirewallRule = { ...tempRule, ruleId: 'new', contextProfiles: tempRule.profile, appliedTo: 'DFW', action: 'Allow', status: 'Success' };
    this.editSourceDestModalState.set({ isOpen: true, rule: mappedRule, policyId, field, isNewRule: true });
  }

  handleOpenEditServicesModal(policyId: string, rule: IdsIpsRule): void {
      this.editServicesModalState.set({ isOpen: true, rule, policyId });
  }

  handleOpenEditServicesModalForNewRule(): void {
    const policyId = this.addingRuleToPolicyId();
    if (!policyId) return;
    const formState = this.newRuleForm();
    const tempRule: IdsIpsRule = { id: 'new-rule', ...formState };
    this.editServicesModalState.set({ isOpen: true, rule: tempRule, policyId, isNewRule: true });
  }

  handleOpenEditProfilesModal(policyId: string, rule: IdsIpsRule): void {
      this.editProfilesModalState.set({ isOpen: true, rule, policyId });
  }

  handleOpenEditProfilesModalForNewRule(): void {
    const policyId = this.addingRuleToPolicyId();
    if (!policyId) return;
    const formState = this.newRuleForm();
    const tempRule: IdsIpsRule = { id: 'new-rule', ...formState };
    this.editProfilesModalState.set({ isOpen: true, rule: tempRule, policyId, isNewRule: true });
  }

  handleOpenViewMembersModal(groupName: string): void {
    const groupData = mockGroupData[groupName];
    if (groupData) {
      this.viewingGroup.set(groupData);
      this.editSourceDestModalState.update(s => ({ ...s, isOpen: false }));
      this.isViewMembersModalOpen.set(true);
    }
  }

  handleOpenRelatedGroupsModal(group: SelectableGroup): void {
    this.viewingRelatedGroup.set(group);
    this.isRelatedGroupsModalOpen.set(true);
  }

  handleCloseViewMembersModal(): void {
    this.isViewMembersModalOpen.set(false);
    this.editSourceDestModalState.update(s => ({ ...s, isOpen: true }));
  }

  handleAddNewGroup(newGroup: SelectableGroup): void {
    this.availableGroups.update(prev => [newGroup, ...prev]);
  }

  // --- Modal Save/Close Handlers ---
  handleSaveSourceDest(newValue: string): void {
    const state = this.editSourceDestModalState();
    if (!state.field) return;

    if (state.isNewRule) {
      this.newRuleForm.update(form => ({ ...form, [state.field!]: newValue }));
    } else if (state.rule && state.policyId) {
      this.handleRuleUpdate(state.policyId, state.rule.id, state.field, newValue);
    }
    this.editSourceDestModalState.set({ isOpen: false, rule: null, policyId: null, field: null });
  }

  handleSaveServices(newServices: Service[]): void {
      const state = this.editServicesModalState();
      if (state.isNewRule) {
        this.newRuleForm.update(form => ({...form, services: newServices}));
      } else if (state.rule && state.policyId) {
        this.handleRuleUpdate(state.policyId, state.rule.id, 'services', newServices);
      }
      this.editServicesModalState.set({ isOpen: false, rule: null, policyId: null });
  }

  handleSaveProfile(newProfile: string): void {
      const state = this.editProfilesModalState();
      if (state.isNewRule) {
        this.newRuleForm.update(form => ({...form, profile: newProfile}));
      } else if (state.rule && state.policyId) {
        this.handleRuleUpdate(state.policyId, state.rule.id, 'profile', newProfile);
      }
      this.editProfilesModalState.set({ isOpen: false, rule: null, policyId: null });
  }
}

@keyframes aurora {
	0% {
		background-position: 0% 50%;
	}
	50% {
		background-position: 100% 50%;
	}
	100% {
		background-position: 0% 50%;
	}
}

@keyframes slideInUp {
  from {
    opacity: 0;
    transform: translateY(30px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes pulseGlow {
  0% {
    transform: scale(0.95);
    box-shadow: 0 0 0 0 rgba(103, 154, 65, 0.4);
  }
  70% {
    transform: scale(1);
    box-shadow: 0 0 0 20px rgba(103, 154, 65, 0);
  }
  100% {
    transform: scale(0.95);
    box-shadow: 0 0 0 0 rgba(103, 154, 65, 0);
  }
}

@keyframes pulseGlowDark {
  0% {
    transform: scale(0.95);
    box-shadow: 0 0 0 0 rgba(140, 200, 102, 0.4);
  }
  70% {
    transform: scale(1);
    box-shadow: 0 0 0 20px rgba(140, 200, 102, 0);
  }
  100% {
    transform: scale(0.95);
    box-shadow: 0 0 0 0 rgba(140, 200, 102, 0);
  }
}


:host {
  display: block;
  height: 100%;
  overflow: hidden;
  position: relative;
  background: linear-gradient(-45deg, #f0f4f8, #d9e2ec, #f0f4f8, #e0eafc);
  background-size: 400% 400%;
  animation: aurora 18s ease infinite;
}

:host-context(.dark) {
  background: linear-gradient(-45deg, #0f172a, #1e293b, #111827, #1e293b);
  background-size: 400% 400%;
  animation: aurora 25s ease infinite;
}

.getting-started-container {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: flex-end; /* Align content to the right */
  width: 100%;
  height: 100%;
}

.circle-container {
  position: absolute;
  top: 50%;
  left: 0;
  width: 90vh;
  height: 90vh;
  min-width: 700px;
  min-height: 700px;
  transform: translate(-50%, -50%);
  z-index: 0;
}

.circle-track {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  border: 30px solid #679a41;
  border-radius: 50%;
  clip-path: polygon(50% 0, 100% 0, 100% 100%, 50% 100%);
  opacity: 0.3;
}

:host-context(.dark) .circle-track {
  border-color: #8cc866;
  opacity: 0.3;
}

.circle-rotator {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  transition: transform 0.7s cubic-bezier(0.68, -0.55, 0.27, 1.55);
}

.step-item-wrapper {
  position: absolute;
  transform: translate(-50%, -50%);
}

.step-item {
  display: flex;
  align-items: center;
  gap: 1rem;
  background: none;
  border: none;
  cursor: pointer;
  transform-origin: center center;
  padding: 0.5rem;
  border-radius: 1rem;
  position: relative;

  /* Inactive state */
  opacity: 0.4;
  transform: scale(0.7);
  transition: all 0.5s cubic-bezier(0.68, -0.55, 0.27, 1.55);
}

.step-number {
  font-weight: 600;
  color: #9ca3af; /* gray-400 */
  font-size: 2rem;
  transition: all 0.5s ease;
  width: 60px;
  text-align: center;
}

.step-details {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  opacity: 0;
  visibility: hidden;
  transform: translateX(-15px);
  transition: opacity 0.4s ease 0.2s, transform 0.4s ease 0.2s, visibility 0.4s 0.2s;
  white-space: nowrap;
}

.step-icon {
  font-size: 1.5rem;
  color: #4b5563; /* gray-600 */
}

.step-title {
  font-size: 1.125rem;
  font-weight: 600;
  color: #374151; /* gray-700 */
}

.step-item.active {
  background-color: rgba(255, 255, 255, 0.6);
  backdrop-filter: blur(4px);
  opacity: 1;
  transform: scale(1);
}

:host-context(.dark) .step-item.active {
    background-color: rgba(42, 53, 71, 0.6);
}

.step-item.active::after {
  content: '';
  position: absolute;
  top: -10px;
  left: -10px;
  right: -10px;
  bottom: -10px;
  border-radius: 1.25rem;
  z-index: -1;
  box-shadow: 0 0 0 0 rgba(103, 154, 65, 0.4);
  animation: pulseGlow 2s infinite;
}

:host-context(.dark) .step-item.active::after {
    animation-name: pulseGlowDark;
}

.step-item.active .step-number {
  color: #111827; /* gray-900 */
  font-size: 2.5rem;
  font-weight: 800;
}

.step-item.active .step-details {
  opacity: 1;
  visibility: visible;
  transform: translateX(0);
}

/* Active dot */
.step-item.active::before {
  content: '';
  position: absolute;
  left: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 8px;
  height: 8px;
  background-color: #111827;
  border-radius: 50%;
}

:host-context(.dark) .step-number { color: #6b7280; }
:host-context(.dark) .step-item.active .step-number { color: #f9fafb; }
:host-context(.dark) .step-icon { color: #9ca3af; }
:host-context(.dark) .step-title { color: #d1d5db; }
:host-context(.dark) .step-item.active::before { background-color: #f9fafb; }

.content-container {
  width: 50%;
  padding-left: 5%;
  padding-right: 10%;
  position: relative;
  z-index: 10;
}

.content-item > * {
  animation-name: slideInUp;
  animation-duration: 0.6s;
  animation-fill-mode: both;
  animation-timing-function: cubic-bezier(0.215, 0.610, 0.355, 1.000);
}

.content-title {
  display: flex;
  align-items: center;
  gap: 1.5rem;
  font-size: 2rem;
  font-weight: 700;
  color: #374151; /* gray-700 */
}

:host-context(.dark) .content-title {
  color: #d1d5db; /* gray-300 */
}

.content-title .step-number-large {
  animation-delay: 0.1s;
}
.content-title span:last-of-type {
  animation-delay: 0.2s;
}

.content-description {
  margin-top: 1rem;
  font-size: 1rem;
  color: #4b5563; /* gray-600 */
  max-width: 400px;
  line-height: 1.6;
  animation-delay: 0.3s;
}

:host-context(.dark) .content-description {
  color: #9ca3af; /* gray-400 */
}

.content-cta {
  display: inline-flex;
  align-items: center;
  margin-top: 2rem;
  padding: 0.75rem 1.5rem;
  background-color: #679a41;
  color: white;
  font-weight: 600;
  border-radius: 0.5rem;
  text-decoration: none;
  transition: all 0.3s ease;
  box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1);
  animation-delay: 0.4s;
}

.content-cta:hover {
  background-color: #537d34;
  transform: translateY(-2px);
  box-shadow: 0 10px 15px -3px rgb(0 0 0 / 0.1), 0 4px 6px -4px rgb(0 0 0 / 0.1);
}

.step-number-large {
  font-size: 5rem;
  font-weight: 800;
  color: #111827; /* gray-900 */
  line-height: 1;
}

:host-context(.dark) .step-number-large {
  color: #f9fafb;
}

